// Outgoing stats: pro Client + Land → InfluxDB Punkte
var data = msg.payload;
if (!data || !data.clients) return null;

var points = [];
var clients = data.clients;

for (var clientIP in clients) {
    var cl = clients[clientIP];
    var countries = cl.countries || {};

    // Einen Punkt pro Client+Land Kombination
    for (var country in countries) {
        points.push({
            measurement: 'tcpgeo_outgoing',
            tags: {
                client: clientIP,
                country: country
            },
            fields: {
                connections: countries[country],
                total_bytes: cl.bytes || 0
            }
        });
    }

    // Aggregierten Punkt pro Client (Gesamt)
    points.push({
        measurement: 'tcpgeo_outgoing_total',
        tags: {
            client: clientIP
        },
        fields: {
            connections: cl.total || 0,
            bytes: cl.bytes || 0,
            countries_count: Object.keys(countries).length
        }
    });
}

if (points.length === 0) return null;
msg.payload = points;
return msg;

// Incoming stats: pro Port + Land → InfluxDB Punkte
var data = msg.payload;
if (!data || !data.ports) return null;

var points = [];
var ports = data.ports;

for (var portNum in ports) {
    var p = ports[portNum];
    var countries = p.countries || {};
    var lbl = (p.label && p.label.length > 0) ? p.label : 'Port_' + portNum;

    // Einen Punkt pro Port+Land Kombination
    for (var country in countries) {
        if (!country || country.length === 0) continue;
        points.push({
            measurement: 'tcpgeo_incoming',
            tags: {
                port: portNum,
                label: lbl,
                country: country
            },
            fields: {
                connections: countries[country]
            }
        });
    }

    // Aggregiert pro Port
    points.push({
        measurement: 'tcpgeo_incoming_total',
        tags: {
            port: portNum,
            label: lbl
        },
        fields: {
            connections: p.total || 0,
            countries_count: Object.keys(countries).length
        }
    });
}

if (points.length === 0) return null;
msg.payload = points;
return msg;

// Client Detail: pro Client + Ziel (Land/Stadt/Port) → InfluxDB
var data = msg.payload;
if (!data || !data.clients) return null;

var points = [];
var clients = data.clients;

for (var clientIP in clients) {
    var entries = clients[clientIP];
    if (!Array.isArray(entries)) continue;

    for (var i = 0; i < entries.length; i++) {
        var e = entries[i];
        var tags = {
            client: clientIP,
            country: e.country || 'unknown',
            port: String(e.port || 0)
        };
        if (e.city && e.city.length > 0) tags.city = e.city;
        if (e.label && e.label.length > 0) tags.label = e.label;
        else tags.label = 'Port_' + (e.port || 0);
        points.push({
            measurement: 'tcpgeo_client_detail',
            tags: tags,
            fields: {
                count: e.count || 0,
                bytes: e.bytes || 0
            }
        });
    }
}

if (points.length === 0) return null;
msg.payload = points;
return msg;

// Recent connections: jede Verbindung als eigenen Punkt
var data = msg.payload;
if (!data || !data.connections) return null;

var conns = data.connections;
var points = [];

for (var i = 0; i < conns.length; i++) {
    var c = conns[i];
    var tags = {
        direction: c.dir || 'unknown',
        client: c.client || 'unknown',
        country: c.country || 'unknown',
        port: String(c.port || 0)
    };
    if (c.city && c.city.length > 0) tags.city = c.city;
    if (c.label && c.label.length > 0) tags.label = c.label;
    else tags.label = 'Port_' + (c.port || 0);
    points.push({
        measurement: 'tcpgeo_connection',
        tags: tags,
        fields: {
            bytes: c.bytes || 0,
            event: 1
        }
    });
}

if (points.length === 0) return null;

// Status-Punkt: Gesamtanzahl Verbindungen im Snapshot
points.push({
    measurement: 'tcpgeo_status',
    tags: {},
    fields: {
        active_connections: data.count || 0
    }
});

msg.payload = points;
return msg;
